INSERT INTO `assessment_record` VALUES (2,14,12,28,'mild','本次测评得分28分，等级：mild。建议持续关注自身状态。','2026-05-07 00:00:00'),(3,35,14,28,'mild','本次测评得分28分，等级：mild。建议持续关注自身状态。','2026-05-04 00:00:00'),(4,35,1,21,'normal','本次测评得分21分，等级：normal。建议持续关注自身状态。','2026-05-08 00:00:00'),(5,35,15,46,'severe','本次测评得分46分，等级：severe。建议持续关注自身状态。','2026-05-18 00:00:00'),(6,37,7,42,'severe','本次测评得分42分，等级：severe。建议持续关注自身状态。','2026-05-13 00:00:00'),(7,2,1,34,'moderate','本次测评得分34分，等级：moderate。建议持续关注自身状态。','2026-05-07 00:00:00'),(8,36,11,30,'mild','本次测评得分30分，等级：mild。建议持续关注自身状态。','2026-05-11 00:00:00'),(9,14,2,27,'mild','得分27分','2026-05-10 00:00:00'),(10,14,13,27,'mild','得分27分','2026-05-01 00:00:00'),(11,35,9,37,'moderate','得分37分','2026-05-18 00:00:00'),(12,35,5,44,'severe','得分44分','2026-05-17 00:00:00'),(13,35,4,32,'mild','得分32分','2026-05-13 00:00:00'),(14,35,1,36,'moderate','得分36分','2026-05-23 00:00:00'),(15,37,10,30,'mild','得分30分','2026-05-12 00:00:00'),(16,37,12,44,'severe','得分44分','2026-05-10 00:00:00'),(17,37,2,26,'mild','得分26分','2026-05-02 00:00:00'),(18,37,8,23,'normal','得分23分','2026-05-16 00:00:00'),(19,2,10,33,'moderate','得分33分','2026-04-30 00:00:00'),(20,2,11,30,'mild','得分30分','2026-05-03 00:00:00'),(21,2,7,31,'mild','得分31分','2026-05-14 00:00:00'),(22,36,9,38,'moderate','得分38分','2026-05-01 00:00:00'),(23,36,13,27,'mild','得分27分','2026-05-17 00:00:00'),(24,36,13,35,'moderate','得分35分','2026-05-01 00:00:00'),(25,38,14,41,'severe','得分41分','2026-05-22 00:00:00'),(26,38,14,26,'mild','得分26分','2026-05-13 00:00:00'),(27,38,9,32,'mild','得分32分','2026-05-05 00:00:00'),(28,38,2,42,'severe','得分42分','2026-04-29 00:00:00'),(29,39,10,28,'mild','得分28分','2026-05-08 00:00:00'),(30,39,13,22,'normal','得分22分','2026-05-10 00:00:00'),(31,39,10,22,'normal','得分22分','2026-04-29 00:00:00'),(32,39,5,22,'normal','得分22分','2026-05-04 00:00:00');
