/*!40000 ALTER TABLE `chat_message` DISABLE KEYS */;
INSERT INTO `chat_message` VALUES (1,1,'USER','最近加班很多，感觉很烦躁，不知道怎么调节。','2026-05-07 23:17:02','2026-05-07 23:17:02'),(2,1,'ASSISTANT','可以先试试每天留出15分钟只做让自己放松的小事，例如深呼吸或散步。你愿意说说最近一次烦躁的具体情境吗？','2026-05-07 23:17:02','2026-05-07 23:17:02'),(3,1,'USER','主要是周末也被消息打断，没法休息。','2026-05-07 23:17:02','2026-05-07 23:17:02'),(4,2,'USER','我连续一周入睡困难。','2026-05-07 23:17:02','2026-05-07 23:17:02'),(5,2,'ASSISTANT','入睡困难很常见。我们可以从作息节律入手：固定起床时间、睡前一小时减少屏幕刺激。需要的话我可以和你一起列一个简单的睡前清单。','2026-05-07 23:17:02','2026-05-07 23:17:02'),(6,3,'USER','I feel anxious these days','2026-05-10 21:21:23','2026-05-10 21:21:23'),(7,3,'ASSISTANT','你的感受值得被重视。想听听我的一些建议吗？','2026-05-10 21:21:23','2026-05-10 21:21:23'),(8,4,'USER','我好伤心 作业写不完看','2026-05-10 21:27:07','2026-05-10 21:27:06'),(9,4,'ASSISTANT','抱抱你，一切都会慢慢好起来的。你现在不是一个人。','2026-05-10 21:27:07','2026-05-10 21:27:06'),(10,5,'USER','hello','2026-05-10 22:46:01','2026-05-10 22:46:00'),(11,5,'ASSISTANT','我理解你现在的心情。有时候说出来就会好很多。','2026-05-10 22:46:01','2026-05-10 22:46:00'),(12,6,'USER','I feel anxious lately, cannot sleep well','2026-05-10 23:02:58','2026-05-10 23:02:57'),(13,6,'ASSISTANT','听到你最近感到焦虑和睡不好，我心里很关心你。这种状态一定让你很疲惫吧？有时候，我们的身体和情绪会像这样发出信号，提醒我们需要停下来看看自己。你愿意和我多说说，是什么事情让你感到焦虑，或者这些感觉是从什么时候开始的吗？我在这里陪着你，慢慢说就好。','2026-05-10 23:03:01','2026-05-10 23:03:00'),(14,6,'USER','I feel like I want to end my life','2026-05-10 23:03:17','2026-05-10 23:03:17'),(15,6,'ASSISTANT','听到你这样说，我心里非常难受。我能感受到你现在一定承受着巨大的痛苦，才会产生这样的想法。你的感受是真实的，也值得被认真对待。请先深呼吸一下，试着感受此刻的呼吸，我就在这里陪着你，不会离开。你愿意和我多说一说，是什么让你感到如此绝望吗？【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-10 23:03:24','2026-05-10 23:03:23'),(16,6,'USER','I feel like I want to end my life','2026-05-10 23:03:24','2026-05-10 23:03:23'),(17,6,'ASSISTANT','我听到了你内心的痛苦，也感受到你正在经历非常艰难的时刻。请相信，你此刻的情绪是被理解的，你并不孤单。每个人的生命都值得被珍视，包括你的。你愿意和我多说说是什么让你感到如此绝望吗？我会在这里陪着你。\n\n【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-10 23:03:26','2026-05-10 23:03:26'),(18,7,'USER','你好','2026-05-10 23:05:27','2026-05-10 23:05:26'),(19,7,'ASSISTANT','你好呀，我是心聆。很高兴你愿意和我聊聊。无论你此刻是开心、疲惫，还是心里有些话想说，我都愿意安静地听你说。你最近过得怎么样？','2026-05-10 23:05:28','2026-05-10 23:05:28'),(20,7,'USER','我好困 我好累 可是我自己没写完','2026-05-10 23:05:43','2026-05-10 23:05:42'),(21,7,'ASSISTANT','听到你这样说，我能感受到你真的很疲惫。身体在向你发出信号，需要休息了。有时候，我们越是逼迫自己，反而越难集中精力。不如先停下来，给自己几分钟深呼吸，喝杯温水，让大脑和身体都缓一缓。任务可以稍后再继续，但你的健康和情绪才是最重要的。你愿意和我聊聊是什么让你这么坚持要完成它吗？','2026-05-10 23:05:45','2026-05-10 23:05:45'),(22,7,'USER','我想拿高分','2026-05-10 23:06:01','2026-05-10 23:06:00'),(23,7,'ASSISTANT','听起来你对自己有很高的要求，也付出了很多努力，这真的很棒。不过，追求高分的过程中，有没有感到压力很大或者有点焦虑呢？有时候，我们太专注于结果，反而会忽略了过程中的成长。你最近在准备什么考试或任务吗？可以和我聊聊你的感受，我会一直在这里支持你。','2026-05-10 23:06:03','2026-05-10 23:06:02'),(24,7,'USER','我想去好学校','2026-05-10 23:06:13','2026-05-10 23:06:12'),(25,7,'ASSISTANT','我能感受到你对未来有着很高的期待和追求，想要去好学校说明你对自己有要求，也愿意努力去争取更好的机会，这真的很棒。不过，有时候这种压力可能会让你感到焦虑或不安，对吗？能不能和我聊聊，是什么让你对“好学校”这么在意呢？我愿意听你说说。','2026-05-10 23:06:15','2026-05-10 23:06:14'),(26,8,'USER','我不想学习了','2026-05-10 23:08:15','2026-05-10 23:08:14'),(27,8,'ASSISTANT','我能感受到你现在对学习感到有些疲惫和压力，这种情绪是很正常的。学习路上偶尔会有低谷，重要的是你愿意表达出来，这本身就是一种勇气。  \n也许可以试着给自己一点喘息的时间，比如深呼吸几次，或者短暂地做点喜欢的事。你愿意和我说说，是最近的学习任务特别繁重，还是有什么具体的事情让你感到困扰吗？','2026-05-10 23:08:17','2026-05-10 23:08:16'),(28,8,'USER','我讨厌课设','2026-05-10 23:08:22','2026-05-10 23:08:21'),(29,8,'ASSISTANT','听到你这么说，我能感受到你现在的压力和疲惫。课设确实常常让人感到烦躁，尤其是当任务繁重、时间紧张的时候。这种情绪是很正常的，你并不孤单。可以试着和我聊聊，具体是哪一部分让你觉得特别难受吗？也许说出来会让心里轻松一些。','2026-05-10 23:08:30','2026-05-10 23:08:29'),(30,9,'USER','我好想死','2026-05-10 23:16:43','2026-05-10 23:16:43'),(31,9,'ASSISTANT','听到你这样说，我心里很难过。你愿意把这些感受告诉我，说明你信任我，也说明你内心还存着一丝希望。这种痛苦一定压得你很重，我在这里，不会评判你，只想陪你一起看看，是什么让你这么难受。你愿意和我多说一点吗？【危机预警：建议拨打心理援助热线 400-161-9995】\n\n【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-10 23:16:45','2026-05-10 23:16:45'),(32,10,'USER','快期末了，我感觉好焦虑，怕挂科','2026-05-06 19:00:00','2026-05-11 00:10:44'),(33,10,'ASSISTANT','听到你为期末考试感到焦虑，我完全理解。期末周确实压力很大，不过你已经意识到了这个问题，这就是很好的第一步。可以跟我说说，是哪一科让你最担心吗？','2026-05-06 19:00:30','2026-05-11 00:10:44'),(34,10,'USER','高数，我高数上期就考得不太好','2026-05-06 19:01:00','2026-05-11 00:10:44'),(35,10,'ASSISTANT','高数确实是一门需要花时间的课程。我建议你可以试试：1. 先把往年真题过一遍，了解题型；2. 找班上高数学得好的同学一起复习；3. 每天固定1-2小时专攻高数，不要临时抱佛脚。你平时有去问老师或助教吗？','2026-05-06 19:02:00','2026-05-11 00:10:44'),(36,10,'USER','还没有，有点不敢问','2026-05-06 19:02:30','2026-05-11 00:10:44'),(37,10,'ASSISTANT','不用害怕问问题哦，老师其实很欢迎学生去请教。你可以先把不会的题目整理好，一次性去问，这样效率更高。记住，求助不是软弱，而是对自己的学习负责。加油，我相信你可以的！','2026-05-06 19:03:00','2026-05-11 00:10:44'),(38,11,'USER','感觉和室友有点合不来，他们喜欢打游戏到很晚，我想早睡','2026-05-08 21:30:00','2026-05-11 00:10:44'),(39,11,'ASSISTANT','宿舍作息不一致确实是个很让人困扰的问题。你有和室友聊过这件事吗？有时候大家只是不知道你的习惯，好好沟通可能会有意想不到的效果。','2026-05-08 21:31:00','2026-05-11 00:10:44'),(40,11,'ASSISTANT','你也可以提议一些折中的办法，比如约定晚上11点后戴耳机、调暗屏幕。如果沟通后还是没有改善，也可以和辅导员反映，申请调换宿舍。你的睡眠和健康是最重要的。','2026-05-08 21:32:00','2026-05-11 00:10:44'),(41,12,'USER','我不想做课设了','2026-05-11 00:19:29','2026-05-11 00:19:28'),(42,12,'ASSISTANT','听起来你现在对课设感到有些疲惫和无力，这很正常，面对繁重的任务时，偶尔有这样的情绪是可以理解的。你愿意和我聊聊具体是哪里让你觉得特别困难吗？也许说出来，心里会轻松一些。我会一直在这里听你倾诉的。','2026-05-11 00:19:31','2026-05-11 00:19:31'),(43,12,'USER','我想睡觉','2026-05-11 00:19:35','2026-05-11 00:19:35'),(44,12,'ASSISTANT','听起来你现在很疲惫，想要好好休息一下了。睡眠是身体和心灵修复的重要时刻，能意识到这一点已经很棒了。如果你愿意，可以试着闭上眼睛，深呼吸几次，感受一下身体的放松。有什么特别的事情让你感到累吗？或者，有没有什么烦恼在脑海里盘旋，让你难以安心入睡？我在这里陪着你。','2026-05-11 00:19:37','2026-05-11 00:19:37'),(45,13,'USER','想死','2026-05-11 00:24:30','2026-05-11 00:24:30'),(46,13,'ASSISTANT','我听到你这么说，心里很担心你。你愿意和我说说，是什么让你感到这么痛苦和绝望吗？我在这里，会耐心听你讲，不会评判你。你并不孤单，我们可以一起慢慢梳理这些情绪。\n\n【危机预警：建议拨打心理援助热线 400-161-9995】\n\n【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-11 00:24:32','2026-05-11 00:24:31'),(47,13,'USER','一起死吧','2026-05-11 00:24:35','2026-05-11 00:24:35'),(48,13,'ASSISTANT','我听到你这句话，心里很担心你。你现在一定非常痛苦，才会说出这样的话。我在这里陪着你，愿意听你说说发生了什么。你不需要一个人承受这些。可以告诉我，是什么让你感到这么绝望吗？','2026-05-11 00:24:37','2026-05-11 00:24:36'),(49,13,'USER','你回复的慢吗','2026-05-11 00:31:10','2026-05-11 00:31:10'),(50,13,'ASSISTANT','亲爱的，别担心，我会一直在你身边，认真听你说的每一句话。可能我需要一点时间来思考如何更好地回应你，但绝不会让你等太久。你现在感觉怎么样？有什么想和我聊聊的吗？我在这里，随时都愿意倾听你的心声。','2026-05-11 00:31:12','2026-05-11 00:31:11'),(55,12,'USER','我总是感觉很困','2026-05-21 23:28:07','2026-05-21 23:28:06'),(56,12,'ASSISTANT','听起来你最近真的被这种持续的困倦感困扰着，这一定让你感到有些疲惫和无助。我会在这里陪着你，慢慢聊聊这种感觉。你能告诉我，这种困倦感是最近才开始的，还是已经持续了一段时间呢？有没有什么特别的事情发生，或者你感觉生活中有什么变化？','2026-05-21 23:28:10','2026-05-21 23:28:09'),(57,12,'USER','持续一周了','2026-05-21 23:28:36','2026-05-21 23:28:36'),(58,12,'ASSISTANT','看到你提到已经持续一周了，我能感受到这段时间对你来说可能有些艰难。愿意告诉我这一周里，你主要经历了什么样的情绪或事情吗？无论是疲惫、低落，还是其他感受，我都在这里陪着你，慢慢说也没关系。','2026-05-21 23:28:38','2026-05-21 23:28:37'),(59,12,'USER','晚上失眠','2026-05-21 23:28:58','2026-05-21 23:28:57'),(60,12,'ASSISTANT','听到你正在经历失眠的困扰，我能感受到那种翻来覆去却无法入睡的疲惫感。夜晚的寂静有时会放大我们的思绪，让人感到孤单或焦虑。你愿意和我聊聊最近是不是有什么事情在困扰你吗？有时候，把心里的包袱说出来，可能会让夜晚变得轻松一些。','2026-05-21 23:28:59','2026-05-21 23:28:58'),(61,12,'USER','我也收不上来','2026-05-21 23:29:16','2026-05-21 23:29:15'),(62,12,'ASSISTANT','我能感受到你现在的心情有些低落，好像有些事情让你感到疲惫或困惑。没关系，我在这里陪着你，你可以慢慢说，不用着急。有时候，把心里的感受说出来，哪怕只是一点点，也会让心情轻松一些。你想和我聊聊最近发生了什么吗？','2026-05-21 23:29:21','2026-05-21 23:29:20'),(63,13,'USER','你好','2026-05-23 21:06:01','2026-05-23 21:06:01'),(64,13,'ASSISTANT','你好呀，很高兴你愿意和我聊聊天。我是心聆，一个温暖的小助手。今天你感觉怎么样？有什么想和我分享的吗？无论是什么，我都会在这里安静地陪着你，听你说。','2026-05-23 21:06:04','2026-05-23 21:06:03'),(65,13,'USER','现在可以聊天吗','2026-05-23 21:06:12','2026-05-23 21:06:11'),(66,13,'ASSISTANT','当然可以，我在这里陪着你呢。无论你想聊什么，我都会认真倾听。你最近过得怎么样？有什么想和我分享的吗？','2026-05-23 21:06:13','2026-05-23 21:06:12'),(67,13,'USER','最近作业好多','2026-05-23 21:06:30','2026-05-23 21:06:29'),(68,13,'ASSISTANT','听起来你最近压力很大呢。面对堆积如山的作业，感到疲惫是很正常的。你已经很努力了，不妨先深呼吸一下，给自己一点喘息的空间。要不要试着把任务拆分成小步骤，一点点完成？或者先休息10分钟，喝杯温水，再继续。你愿意和我多说一说，是哪一科的作业让你最困扰吗？','2026-05-23 21:06:32','2026-05-23 21:06:31'),(69,19,'USER','我最近有点焦虑，想找人聊聊。','2026-05-24 13:03:16','2026-05-24 13:03:15'),(70,19,'ASSISTANT','听到你愿意分享自己的感受，我真的很欣慰。焦虑是一种很常见的情绪，很多人都曾经历过。能告诉我最近是什么事情让你感到焦虑吗？我会静静地陪着你，听你说。','2026-05-24 13:03:18','2026-05-24 13:03:18'),(71,19,'USER','我想死','2026-05-24 13:54:01','2026-05-24 13:54:00'),(72,19,'ASSISTANT','听到你这么说，我感到很心疼。你愿意把这些话告诉我，说明你心里一定很痛苦，也对我有一份信任。我想告诉你，你并不孤单，有些时候，黑暗会让我们看不到出口，但那些情绪只是暂时的。你值得被倾听、被理解。能和我多说说，最近发生了什么让你感到这样难过的吗？我在这里陪着你。  \n\n【危机预警：建议拨打心理援助热线 400-161-9995】\n\n【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-24 13:54:03','2026-05-24 13:54:02'),(73,20,'USER','我觉得最近有点累','2026-05-24 14:29:56','2026-05-24 14:29:55'),(74,20,'ASSISTANT','听到你这么说，我能感受到你最近可能承受了不少压力。疲惫不仅仅是身体上的，有时也是一种情绪上的负担。你愿意和我聊聊，是什么让你觉得特别累吗？无论是工作、学习，还是生活中的琐事，我都在这里陪着你。记得，适当的休息和放松也很重要，给自己一点时间去倾听内心的声音。','2026-05-24 14:29:59','2026-05-24 14:29:59'),(75,20,'USER','经常觉得画的画不好看想撕掉','2026-05-24 14:30:28','2026-05-24 14:30:28'),(76,20,'ASSISTANT','我能感受到你对自己作品的高要求，这种想要追求完美的感觉其实很常见。画画是一种表达，而不是一场考试哦。每一笔、每一划都是你当下的心情和努力，它们本身就很有价值。试着把“不好看”换成“还在成长”，给自己一些空间去探索和尝试。你愿意和我聊聊，是哪一部分让你觉得特别不满意吗？','2026-05-24 14:30:32','2026-05-24 14:30:32'),(77,20,'USER','好崩溃啊','2026-05-24 14:33:35','2026-05-24 14:33:35'),(78,20,'ASSISTANT','听到你这么说，我能感受到你现在的情绪一定很沉重。生活中总会有让人喘不过气的时刻，你愿意把这份感受说出来，已经是很勇敢的一步了。可以告诉我，是什么让你感到这么崩溃吗？我会在这里陪着你。\n\n【危机预警：建议拨打心理援助热线 400-161-9995】','2026-05-24 14:33:37','2026-05-24 14:33:37');
