INSERT INTO `crisis_alert` VALUES (1,14,5,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:活不下去(5级) | AI分析:AI识别为高危(5级) | 情绪分:2.5(4级) | 最终:5级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-21 00:00:00','2026-05-24 13:40:37'),(2,36,5,'PENDING',NULL,NULL,'情绪分触发预警 | 关键词:未命中 | AI分析:-(-) | 情绪分:2.8(4级) | 连续低分:5天 | 最终:5级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-23 00:00:00','2026-05-24 13:40:37'),(3,2,3,'PENDING',NULL,NULL,'日记触发预警 | 关键词:崩溃(3级) | AI分析:AI识别为中危(3级) | 情绪分:4.5(0级) | 最终:3级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-23 00:00:00','2026-05-24 13:40:37'),(4,39,3,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:未命中 | AI分析:AI识别为中危(3级) | 情绪分:3.5(2级) | 最终:3级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-23 00:00:00','2026-05-24 13:40:37'),(5,5,2,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:未命中 | AI分析:AI识别为需关注(2级) | 情绪分:5.0(0级) | 最终:2级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-24 00:00:00','2026-05-24 13:40:37'),(6,18,2,'PENDING',NULL,NULL,'日记触发预警 | 关键词:没有意义(2级) | AI分析:AI识别为需关注(2级) | 情绪分:5.5(0级) | 最终:2级',NULL,NULL,0,NULL,NULL,NULL,'2026-05-21 00:00:00','2026-05-24 13:40:37'),(8,14,5,'PENDING',NULL,NULL,'日记触发预警 | 关键词:活不下去(5级) | AI分析:已跳过(高危关键词直接触发)(0级) | 情绪分:5.0(0级) | 最终:5级 | 原文:我真的活不下去了，太痛苦了',NULL,NULL,0,NULL,NULL,NULL,'2026-05-24 13:51:35','2026-05-24 13:51:35'),(9,14,5,'RESOLVED',NULL,NULL,'日记触发预警 | 关键词:崩溃(3级) | AI分析:AI识别为高危(4级) | 情绪分:5.0(0级) | 最终:5级 | 近24h同类触发1次,已升级 | 原文:最近真的很崩溃，感觉撑不下去了',1,'已处理',1,'2026-05-24 14:19:14','电话','[05-24 14:19] 电话 → 李芳(母亲/13900139000) | 联系成功\n[05-24 14:18] 短信 → 王伟(父亲/13800138000) | 短信未回复\n[05-24 14:18] 电话 → 王伟(父亲/13800138000) | 电话未接通','2026-05-24 13:51:48','2026-05-24 13:51:48'),(10,35,5,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:想死(5级) | AI分析:已跳过(高危关键词直接触发)(0级) | 情绪分:6.3(0级) | 最终:5级 | 原文:我想死',NULL,NULL,1,'2026-05-24 14:18:14','电话','[05-24 14:18] 电话 → 妍妍(同学/13432135798) | 电话未接通','2026-05-24 13:54:01','2026-05-24 13:54:01'),(11,39,2,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:未命中 | AI分析:AI识别为轻微(1级) | 情绪分:6.5(0级) | 最终:2级 | 原文:经常觉得画的画不好看想撕掉',NULL,NULL,0,NULL,NULL,NULL,'2026-05-24 14:30:30','2026-05-24 14:30:30'),(12,39,3,'PENDING',NULL,NULL,'AI对话触发预警 | 关键词:崩溃(3级) | AI分析:AI识别为中危(3级) | 情绪分:6.5(0级) | 最终:3级 | 原文:好崩溃啊',NULL,NULL,0,NULL,NULL,NULL,'2026-05-24 14:33:36','2026-05-24 14:33:36');
