INSERT INTO `diary` VALUES (1,2,NULL,'今天完成了项目阶段性汇报，略有紧张但整体顺利。','平静,期待',72.50,'积极,成就感',NULL,NULL,'2026-05-07 23:17:02','2026-05-07 23:17:02'),(2,2,NULL,'晚上失眠，脑子里一直在想下周的安排。','焦虑,疲惫',38.00,'焦虑,压力',NULL,NULL,'2026-05-07 23:17:02','2026-05-07 23:17:02'),(3,3,NULL,'和朋友散步聊天，心情放松了很多。','放松,愉悦',85.00,'愉悦,社交支持',NULL,NULL,'2026-05-07 23:17:02','2026-05-07 23:17:02'),(4,1,NULL,'Updated content.','calm',NULL,NULL,NULL,NULL,'2026-05-10 20:48:34','2026-05-10 20:48:34'),(5,7,NULL,'哈哈哈哈哈','开心',NULL,NULL,NULL,NULL,'2026-05-10 20:50:42','2026-05-10 20:50:42'),(6,1,NULL,'Test diary entry.','happy',NULL,NULL,NULL,NULL,'2026-05-10 21:02:38','2026-05-10 21:02:38'),(7,1,'Anxious Day','I feel so anxious and worried about everything','焦虑',30.00,NULL,NULL,NULL,'2026-05-10 21:55:44','2026-05-10 21:55:44'),(9,7,NULL,'想死','平静',50.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-10 23:09:44','2026-05-10 23:09:44'),(10,1,'audit','audit check','一般',50.00,NULL,NULL,NULL,'2026-05-10 23:12:45','2026-05-10 23:12:45'),(11,14,'新学期的第一次班会','今天班级开了新学期第一次班会，辅导员讲了这学期的安排。感觉时间过得好快，转眼都大二下学期了。有点焦虑这学期的课程难度，希望自己能跟得上。','焦虑',35.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-04 20:30:00','2026-05-11 00:10:44'),(12,14,'和室友一起打篮球','下午没课，和室友去操场打了两个小时篮球，出了一身汗，感觉整个人都轻松了很多。晚上一起去食堂吃了麻辣香锅，开心！','开心',82.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-05 18:15:00','2026-05-11 00:10:44'),(13,14,'高数作业好难','在图书馆泡了一下午做高数作业，题目好难，卡在一道积分题上好久。周围的同学好像都会做，有点挫败感。不过最后还是解出来了，松了口气。','焦虑',50.00,NULL,NULL,'/uploads/0d5d3639-9db0-4f8b-9ebf-e9195f53aa82.jpg','2026-05-05 21:00:00','2026-05-11 00:10:44'),(14,14,'和爸妈视频通话','晚上和爸妈视频了一个小时，聊了聊最近的生活。妈妈说给我寄了家乡的腊肠，好期待。虽然在学校有时候会觉得孤独，但听到家人的声音就很安心。','平静',50.00,NULL,NULL,'/uploads/7a8b9a64-b401-4f38-a622-f1f26bba872d.png','2026-05-06 20:00:00','2026-05-11 00:10:44'),(15,14,'社团活动圆满成功','作为社团的副部长，今天负责组织了春季招新活动，来了好多新生报名。虽然前前后后忙了整整一周，但看到活动顺利进行，真的很有成就感！','开心',50.00,NULL,NULL,'/uploads/b23fae93-5db3-4225-a8ac-e3f2954a60e7.png','2026-05-07 17:30:00','2026-05-11 00:10:44'),(16,14,'突然想家了','晚上回到宿舍，看到舍友都在各忙各的，突然觉得好想家。翻手机里和家人的合照，眼泪不争气地流下来了。什么时候才能变得更坚强一点呢。','难过',22.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-08 22:10:00','2026-05-11 00:10:44'),(17,14,'期末复习计划','今天制定了期末复习计划表，把剩下一个月的复习时间安排得满满当当的。虽然有点紧张怕时间不够，但有计划总比没有好！加油加油！','平静',60.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-09 16:00:00','2026-05-11 00:10:44'),(18,14,'周末在图书馆自习','周末图书馆人好多，八点来就没位置了，好不容易在三楼角落找到个座。复习了英语和专业课，效率还不错。中午去食堂吃了最爱吃的酸菜鱼，满足~','平静',50.00,NULL,NULL,'/uploads/9ba28976-67dd-4531-b85a-98ee2e9e7be3.jpg','2026-05-10 11:30:00','2026-05-11 00:10:44'),(20,5,NULL,'哈哈哈','开心',50.00,NULL,NULL,NULL,'2026-05-23 21:14:41','2026-05-23 21:14:41'),(21,35,'哈哈哈','哈哈','一般',50.00,NULL,NULL,NULL,'2026-05-24 10:17:37','2026-05-24 10:17:37'),(22,14,'今天很难受','感觉要崩溃了，什么都不想做','悲伤',25.00,NULL,NULL,NULL,'2026-05-24 11:39:24','2026-05-24 11:39:24'),(23,14,'test','真的崩溃了，感觉好累','悲伤',25.00,NULL,NULL,NULL,'2026-05-24 11:43:54','2026-05-24 11:43:54'),(24,14,'test','最近真的好焦虑，晚上睡不着，担心考试','焦虑',30.00,NULL,NULL,NULL,'2026-05-24 11:51:10','2026-05-24 11:51:10'),(25,14,'t1','感觉活不下去了，真的好绝望','悲伤',25.00,NULL,NULL,NULL,'2026-05-24 12:01:57','2026-05-24 12:01:57'),(26,14,'t2','今天很焦虑，担心考试，心情压抑','焦虑',30.00,NULL,NULL,NULL,'2026-05-24 12:01:58','2026-05-24 12:01:58'),(27,14,'t3','今天天气不错，心情很好','一般',50.00,NULL,NULL,NULL,'2026-05-24 12:01:59','2026-05-24 12:01:59'),(28,14,'今天的课好多','今天上了六节课，真的好累。不过下午和同学一起吃了饭，聊聊天心情好多了。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 13:25:00','2026-05-24 13:40:37'),(29,14,'有点焦虑','快要期中考试了，感觉复习不完。晚上睡不着一直在想题目。',NULL,NULL,NULL,NULL,NULL,'2026-05-05 15:45:00','2026-05-24 13:40:37'),(30,14,'开心的一天','今天数据结构课居然答对了老师的问题！被表扬了很开心。',NULL,NULL,NULL,NULL,NULL,'2026-05-06 09:44:00','2026-05-24 13:40:37'),(31,14,'和室友吵架了','因为一点小事和室友闹矛盾了，现在有点后悔，但也不知道怎么开口。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 08:03:00','2026-05-24 13:40:37'),(32,14,'周末放松','周末去操场跑了五圈，流了一身汗，感觉整个人都轻松了。',NULL,NULL,NULL,NULL,NULL,'2026-05-24 12:01:00','2026-05-24 13:40:37'),(33,14,'想家了','离家已经两个月了，有点想妈妈做的饭。打电话回家聊了好久。',NULL,NULL,NULL,NULL,NULL,'2026-05-07 19:25:00','2026-05-24 13:40:37'),(34,14,'今天的感悟','今天听了心理讲座，老师说适当的压力有助于成长。我觉得有道理。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 20:40:00','2026-05-24 13:40:37'),(35,14,'普通的一天','没什么特别的事，上课吃饭写作业，平平淡淡也挺好。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 08:31:00','2026-05-24 13:40:37'),(36,35,'今天心情不错','今天英语演讲表现很好，老师给了很高的评价。努力没有白费！',NULL,NULL,NULL,NULL,NULL,'2026-05-14 09:14:00','2026-05-24 13:40:37'),(37,35,'有点累了','连续三天早起背单词，有点撑不住。今晚早点睡吧。',NULL,NULL,NULL,NULL,NULL,'2026-05-06 22:19:00','2026-05-24 13:40:37'),(38,35,'闺蜜来访','好朋友从隔壁学校过来找我玩，一起逛了校园聊了很多。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 13:01:00','2026-05-24 13:40:37'),(39,35,'学习计划','制定了新的学习计划，希望能坚持下去。加油！',NULL,NULL,NULL,NULL,NULL,'2026-05-14 10:16:00','2026-05-24 13:40:37'),(40,35,'收到礼物','生日收到了朋友送的书，很开心。被人惦记的感觉真好。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 12:07:00','2026-05-24 13:40:37'),(41,35,'下雨天','今天下雨了，一个人在图书馆看了一下午的书，很安静。',NULL,NULL,NULL,NULL,NULL,'2026-05-16 15:45:00','2026-05-24 13:40:37'),(42,35,'运动打卡','今天去健身房练了一个小时，虽然累但很充实。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 16:52:00','2026-05-24 13:40:37'),(43,35,'晚安','每天睡前写日记已经成了习惯，记录生活的小确幸。',NULL,NULL,NULL,NULL,NULL,'2026-05-06 16:19:00','2026-05-24 13:40:37'),(44,36,'压力很大','最近真的压力很大，代码写不出来，晚上睡不着觉。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 12:08:00','2026-05-24 13:40:37'),(45,36,'又一次失眠','凌晨三点还醒着，脑子里全是乱七八糟的想法。',NULL,NULL,NULL,NULL,NULL,'2026-05-23 16:53:00','2026-05-24 13:40:37'),(46,36,'不想上课','今天翘课了，不想见任何人，就想一个人待着。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 21:37:00','2026-05-24 13:40:37'),(47,36,'感觉好点了','今天去看了心理咨询老师，聊完之后感觉轻松了一点点。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 08:51:00','2026-05-24 13:40:37'),(48,36,'谢谢关心','室友发现我不对劲，主动找我聊天。原来还是有人在关心我的。',NULL,NULL,NULL,NULL,NULL,'2026-05-22 09:37:00','2026-05-24 13:40:37'),(49,36,'慢慢来','老师说恢复需要时间，不能急。我试着接受这个状态。',NULL,NULL,NULL,NULL,NULL,'2026-05-23 08:50:00','2026-05-24 13:40:37'),(50,36,'今天出去走了走','在校园里走了一圈，秋天的风很舒服。',NULL,NULL,NULL,NULL,NULL,'2026-05-16 12:10:00','2026-05-24 13:40:37'),(51,36,'记录一下','最近开始吃药了，希望能慢慢好起来。',NULL,NULL,NULL,NULL,NULL,'2026-05-05 11:37:00','2026-05-24 13:40:37'),(52,37,'心理咨询课','今天上了心理咨询课，学到了很多实用的倾听技巧。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 20:11:00','2026-05-24 13:40:37'),(53,37,'帮助同学','有同学来找我倾诉，我很认真地听完了。能帮到别人很开心。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 09:59:00','2026-05-24 13:40:37'),(54,37,'读书笔记','最近在读一本关于心理咨询的书，很受触动。',NULL,NULL,NULL,NULL,NULL,'2026-05-17 10:14:00','2026-05-24 13:40:37'),(55,37,'实习申请','投了一家心理咨询机构的实习，希望能过。',NULL,NULL,NULL,NULL,NULL,'2026-05-05 19:06:00','2026-05-24 13:40:37'),(56,37,'和朋友聚餐','和几个好朋友一起吃了火锅，聊得很开心。',NULL,NULL,NULL,NULL,NULL,'2026-05-17 11:32:00','2026-05-24 13:40:37'),(57,37,'自我反思','今天反思了一下自己的沟通方式，还有很多需要改进的地方。',NULL,NULL,NULL,NULL,NULL,'2026-05-07 21:04:00','2026-05-24 13:40:37'),(58,2,'学习打卡','今天在图书馆待了一整天，把作业写完了。',NULL,NULL,NULL,NULL,NULL,'2026-05-08 22:24:00','2026-05-24 13:40:37'),(59,2,'打球去了','下午和同学打了篮球，出了很多汗，很爽。',NULL,NULL,NULL,NULL,NULL,'2026-05-05 21:33:00','2026-05-24 13:40:37'),(60,2,'周末日常','周末睡了个懒觉，然后去吃了好吃的。',NULL,NULL,NULL,NULL,NULL,'2026-05-17 19:46:00','2026-05-24 13:40:37'),(61,39,'画了新作品','今天完成了一幅水彩画，自己很满意。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 19:16:00','2026-05-24 13:40:37'),(62,39,'灵感来了','走在路上突然有了灵感，赶紧回宿舍画了下来。',NULL,NULL,NULL,NULL,NULL,'2026-05-08 21:06:00','2026-05-24 13:40:37'),(63,39,'被老师表扬了','老师说我的画进步很大，开心！',NULL,NULL,NULL,NULL,NULL,'2026-05-18 11:09:00','2026-05-24 13:40:37'),(64,39,'画画真的能治愈心情','每次心情不好的时候画画就能平静下来。',NULL,NULL,NULL,NULL,NULL,'2026-05-13 15:22:00','2026-05-24 13:40:37'),(65,14,'test','我真的活不下去了，太痛苦了','悲伤',25.00,NULL,NULL,NULL,'2026-05-24 13:51:34','2026-05-24 13:51:34'),(66,14,'test2','最近真的很崩溃，感觉撑不下去了','悲伤',25.00,NULL,NULL,NULL,'2026-05-24 13:51:47','2026-05-24 13:51:47'),(67,14,'数据结构好难','今天数据结构课讲二叉树完全听不懂，课后问了同学才勉强理解',NULL,NULL,NULL,NULL,NULL,'2026-05-22 16:46:00','2026-05-24 14:41:48'),(68,14,'和室友夜聊','晚上熄灯后和室友聊了很多关于未来工作人生，发现大家都很迷茫',NULL,NULL,NULL,NULL,NULL,'2026-05-22 17:21:00','2026-05-24 14:41:48'),(69,14,'期中成绩出来了','高数考了78分比预期好一点，下次要更努力',NULL,NULL,NULL,NULL,NULL,'2026-05-05 10:15:00','2026-05-24 14:41:48'),(70,14,'参加了社团活动','今天参加了编程社团的Hackathon，虽然没拿奖但是学到了很多',NULL,NULL,NULL,NULL,NULL,'2026-05-06 11:12:00','2026-05-24 14:41:48'),(71,14,'周五晚上好开心','和室友一起去吃了烧烤，聊了很多开心的事，大学时光真美好',NULL,NULL,NULL,NULL,NULL,'2026-05-17 11:52:00','2026-05-24 14:41:48'),(72,14,'今天效率很高','在图书馆待了6个小时把作业都写完了，希望每天都能这么高效',NULL,NULL,NULL,NULL,NULL,'2026-05-06 12:51:00','2026-05-24 14:41:48'),(73,35,'英语演讲比赛','今天参加了英语演讲比赛，拿了第三名，老师说我的发音进步很大',NULL,NULL,NULL,NULL,NULL,'2026-05-10 17:44:00','2026-05-24 14:41:48'),(74,35,'图书馆的一天','在图书馆泡了一整天把论文写完了，成就感满满',NULL,NULL,NULL,NULL,NULL,'2026-05-12 10:01:00','2026-05-24 14:41:48'),(75,35,'和闺蜜逛街','周末和闺蜜去市区逛街买了一件好看的裙子，果然逛街最治愈',NULL,NULL,NULL,NULL,NULL,'2026-05-06 20:24:00','2026-05-24 14:41:48'),(76,35,'和妈妈视频','和妈妈视频了一个小时她说想我了，我也想回家吃她做的饭',NULL,NULL,NULL,NULL,NULL,'2026-05-20 22:47:00','2026-05-24 14:41:48'),(77,35,'跑步打卡','今天在操场跑了4圈坚持了20分钟，目标是下个月能跑5公里',NULL,NULL,NULL,NULL,NULL,'2026-05-20 10:18:00','2026-05-24 14:41:48'),(78,36,'又是一夜无眠','凌晨四点还醒着脑子里全是代码和bug，为什么别人都能写出来就我不行',NULL,NULL,NULL,NULL,NULL,'2026-05-15 19:47:00','2026-05-24 14:41:48'),(79,36,'不想见人','今天翘了所有课拉上窗帘在宿舍躺了一天，不想让任何人看到我这样子',NULL,NULL,NULL,NULL,NULL,'2026-05-04 09:28:00','2026-05-24 14:41:48'),(80,36,'去了心理咨询中心','终于鼓起勇气去了学校的心理咨询中心，老师很温柔聊完之后轻松了一点',NULL,NULL,NULL,NULL,NULL,'2026-05-23 13:06:00','2026-05-24 14:41:48'),(81,36,'开始吃药了','医生开了药说是可以改善睡眠和情绪，希望能有效果',NULL,NULL,NULL,NULL,NULL,'2026-05-13 14:51:00','2026-05-24 14:41:48'),(82,36,'慢慢好起来','最近睡眠好了一点虽然还会做梦但至少能睡着了，慢慢来吧',NULL,NULL,NULL,NULL,NULL,'2026-05-05 15:38:00','2026-05-24 14:41:48'),(83,37,'心理咨询实践课','今天上了心理咨询的实践课和同学互相扮演咨询师和来访者，收获很大',NULL,NULL,NULL,NULL,NULL,'2026-05-06 09:28:00','2026-05-24 14:41:48'),(84,37,'帮助了一个同学','有个学妹来找我倾诉说最近很焦虑，我用倾听技巧陪她聊了很久她说好多了',NULL,NULL,NULL,NULL,NULL,'2026-05-15 14:09:00','2026-05-24 14:41:48'),(85,37,'收到实习offer','投了好久的实习终于有回复了，一家心理咨询机构让我去面试好紧张',NULL,NULL,NULL,NULL,NULL,'2026-05-06 11:31:00','2026-05-24 14:41:48'),(86,37,'今天被夸了','老师说我在咨询模拟中表现得很自然有做咨询师的天赋，开心',NULL,NULL,NULL,NULL,NULL,'2026-05-12 21:18:00','2026-05-24 14:41:48'),(87,39,'水彩画新作品','花了一整天完成了一幅水彩风景画，准备拿去参加学校的画展',NULL,NULL,NULL,NULL,NULL,'2026-05-23 16:59:00','2026-05-24 14:41:48'),(88,39,'画展入选了','我的作品被选入学校的艺术展了，努力没有白费',NULL,NULL,NULL,NULL,NULL,'2026-05-11 15:27:00','2026-05-24 14:41:48'),(89,39,'和室友一起做饭','周末和室友一起做了火锅，虽然厨房差点被烧了但是好好笑',NULL,NULL,NULL,NULL,NULL,'2026-05-23 12:13:00','2026-05-24 14:41:48'),(90,2,'篮球赛赢了','今天学院篮球赛我们班赢了，我投进了关键球全场都在欢呼',NULL,NULL,NULL,NULL,NULL,'2026-05-14 16:33:00','2026-05-24 14:41:48'),(91,2,'高数作业好难','高数作业写了一个下午才写完，感觉脑细胞死了一大半',NULL,NULL,NULL,NULL,NULL,'2026-05-24 12:25:00','2026-05-24 14:41:48'),(92,2,'和高中同学聚会','周末和几个高中同学约饭，大家变化都好大有人考研有人工作',NULL,NULL,NULL,NULL,NULL,'2026-05-05 16:18:00','2026-05-24 14:41:48'),(93,14,'答辩好紧张','今天毕业答辩，在台上腿都在抖。老师问的问题差点答不上来，还好最后过了！',NULL,NULL,NULL,NULL,NULL,'2026-04-19 23:48:00','2026-05-24 14:46:12'),(94,14,'论文写完了','终于把论文初稿写完了，查重率12%，导师说可以。开心到飞起！',NULL,NULL,NULL,NULL,NULL,'2026-04-14 13:29:00','2026-05-24 14:46:12'),(95,14,'舍友太吵了','舍友打游戏到凌晨两点，键盘敲得飞起。我带上耳塞也睡不着，好烦。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 16:51:00','2026-05-24 14:46:12'),(96,14,'今天又被bug虐了','一个空指针异常调了三个小时，结果是对象没判空。想砸电脑。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 22:34:00','2026-05-24 14:46:12'),(97,14,'拿到了offer','收到了实习offer，虽然是家小公司但总算有地方去了。',NULL,NULL,NULL,NULL,NULL,'2026-05-14 19:53:00','2026-05-24 14:46:12'),(98,14,'和女朋友吵架了','因为一点小事吵架了，她生气了我也不知道怎么哄。好难啊。',NULL,NULL,NULL,NULL,NULL,'2026-05-16 20:57:00','2026-05-24 14:46:12'),(99,14,'爸妈来看我了','爸妈从老家来看我，带了好多吃的。妈妈说我瘦了，其实没有哈哈。',NULL,NULL,NULL,NULL,NULL,'2026-05-19 15:26:00','2026-05-24 14:46:12'),(100,14,'今天真的好累','早八到晚九的课，中间就吃了顿饭。回到宿舍直接瘫了。',NULL,NULL,NULL,NULL,NULL,'2026-05-21 09:30:00','2026-05-24 14:46:12'),(101,35,'教资面试过了','教资面试居然过了！结构化问答紧张得要死，但考官人很好。',NULL,NULL,NULL,NULL,NULL,'2026-04-24 09:08:00','2026-05-24 14:46:12'),(102,35,'今天心情好好','今天阳光特别好的那种，走在路上感觉一切都很美好。',NULL,NULL,NULL,NULL,NULL,'2026-04-29 22:38:00','2026-05-24 14:46:12'),(103,35,'和男朋友约会','他带我去吃了新开的日料店，三文鱼很新鲜。在一起快一年了。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 19:17:00','2026-05-24 14:46:12'),(104,35,'考研还是工作','好纠结啊，家里人想让我考研，但我又想工作。到底怎么选。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 15:46:00','2026-05-24 14:46:12'),(105,35,'今天被导师夸了','论文开题报告导师说写得不错，开心了一整天！',NULL,NULL,NULL,NULL,NULL,'2026-05-16 09:43:00','2026-05-24 14:46:12'),(106,35,'减肥好难','说好要减肥的结果室友带了炸鸡回来，没忍住吃了三块。明天再减吧。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 13:52:00','2026-05-24 14:46:12'),(107,35,'今天下雨不想起','外面下大雨，被窝里好舒服完全不想起床。但还是爬起来去上课了。',NULL,NULL,NULL,NULL,NULL,'2026-05-23 19:32:00','2026-05-24 14:46:12'),(108,36,'又一次失眠','已经连续一周睡不着了，安眠药也不敢多吃。好怕自己撑不住。',NULL,NULL,NULL,NULL,NULL,'2026-04-24 21:54:00','2026-05-24 14:46:12'),(109,36,'去医院了','去看了精神科，确诊了中度抑郁。开了药，希望有用吧。',NULL,NULL,NULL,NULL,NULL,'2026-04-29 14:33:00','2026-05-24 14:46:12'),(110,36,'告诉了妈妈','打电话跟妈妈说了病情，她哭了。我也哭了。好对不起她。',NULL,NULL,NULL,NULL,NULL,'2026-05-04 14:42:00','2026-05-24 14:46:12'),(111,36,'今天很难受','早上起来就莫名想哭，坐在床边发了半小时呆。不想让室友看到。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 18:51:00','2026-05-24 14:46:12'),(112,36,'断药了','药吃完了还没去复诊，今天又失眠到凌晨四点。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 15:41:00','2026-05-24 14:46:12'),(113,36,'复诊结果','医生说有在好转，继续吃药。但我怎么感觉不到呢。',NULL,NULL,NULL,NULL,NULL,'2026-05-16 21:45:00','2026-05-24 14:46:12'),(114,36,'今天出门走了走','在校园里走了走，看到樱花开了。有一瞬间觉得活着也挺好的。',NULL,NULL,NULL,NULL,NULL,'2026-05-20 21:49:00','2026-05-24 14:46:12'),(115,36,'试着去上课','今天去上了一节课，虽然没听进去多少但至少出门了。进步吧。',NULL,NULL,NULL,NULL,NULL,'2026-05-23 17:31:00','2026-05-24 14:46:12'),(116,37,'咨询实习第一天','第一天去心理咨询机构实习，带教老师很专业。要学的东西好多。',NULL,NULL,NULL,NULL,NULL,'2026-04-26 14:02:00','2026-05-24 14:46:12'),(117,37,'和来访者共情','今天听了一个来访者的故事，差点没忍住哭出来。做咨询师真的需要强大的内心。',NULL,NULL,NULL,NULL,NULL,'2026-05-02 20:58:00','2026-05-24 14:46:12'),(118,37,'督导反馈','督导说我的共情能力很强但需要注意边界。收获很大。',NULL,NULL,NULL,NULL,NULL,'2026-05-09 20:25:00','2026-05-24 14:46:12'),(119,37,'读书会分享','今天在读书会上分享了《蛤蟆先生去看心理医生》，大家讨论得很热烈。',NULL,NULL,NULL,NULL,NULL,'2026-05-14 13:39:00','2026-05-24 14:46:12'),(120,37,'和妈妈视频','妈妈说以我为傲，我差点哭了。感觉自己在做有意义的事。',NULL,NULL,NULL,NULL,NULL,'2026-05-19 22:46:00','2026-05-24 14:46:12'),(121,37,'今天有点累','连续做了三个咨询有点累，但看到来访者有变化就觉得值得。',NULL,NULL,NULL,NULL,NULL,'2026-05-22 09:24:00','2026-05-24 14:46:12'),(122,39,'毕业设计好难','毕设选题换了好几个了，每个都不满意。焦虑得掉头发。',NULL,NULL,NULL,NULL,NULL,'2026-04-14 16:08:00','2026-05-24 14:46:12'),(123,39,'画画真的解压','心情不好的时候画画真的能平静下来，今天画到忘记吃饭。',NULL,NULL,NULL,NULL,NULL,'2026-04-29 18:32:00','2026-05-24 14:46:12'),(124,39,'作品被挂出来了','之前参赛的作品被挂在学院走廊里了，每次路过都小小得意一下。',NULL,NULL,NULL,NULL,NULL,'2026-05-06 14:25:00','2026-05-24 14:46:12'),(125,39,'实习面试','去了一家设计公司面试，面试官说我的作品集不错。等消息中。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 13:04:00','2026-05-24 14:46:12'),(126,39,'和室友深夜聊天','聊了各自喜欢的画家，我发现我好喜欢莫奈的风格。',NULL,NULL,NULL,NULL,NULL,'2026-05-18 18:58:00','2026-05-24 14:46:12'),(127,39,'今天画了一幅画','花了一整天画了一幅星空，发给妈妈看她说好看。开心。',NULL,NULL,NULL,NULL,NULL,'2026-05-22 20:56:00','2026-05-24 14:46:12'),(128,2,'学院杯篮球赛','今天学院杯篮球赛我们赢了卫冕冠军！我投了12分，超常发挥。',NULL,NULL,NULL,NULL,NULL,'2026-04-24 21:32:00','2026-05-24 14:46:12'),(129,2,'挂科了','高数上挂科了，55分。暑假要补考，好难受。',NULL,NULL,NULL,NULL,NULL,'2026-04-29 23:46:00','2026-05-24 14:46:12'),(130,2,'补考过了','补考过了！虽然只考了61分但不用重修了，万岁！',NULL,NULL,NULL,NULL,NULL,'2026-05-04 20:33:00','2026-05-24 14:46:12'),(131,2,'和兄弟们喝酒','周末和室友出去喝酒，聊到各自的感情史笑死了。',NULL,NULL,NULL,NULL,NULL,'2026-05-12 23:09:00','2026-05-24 14:46:12'),(132,2,'最近在健身','坚持健身两周了，虽然还没看到腹肌但精神状态好了很多。',NULL,NULL,NULL,NULL,NULL,'2026-05-18 21:50:00','2026-05-24 14:46:12'),(133,2,'今天又去打球了','下午打了两个小时球，出了一身汗。打球真的是最快乐的事。',NULL,NULL,NULL,NULL,NULL,'2026-05-22 21:15:00','2026-05-24 14:46:12');
